import{_ as e,o as t,c as i,a2 as r}from"./chunks/framework.LN3EJxkW.js";const k=JSON.parse('{"title":"ClickHouse、dbt、Airflow、Kafka、Flink 与 Spark 的定位","description":"","frontmatter":{"stage":"intermediate","direction":"backend-data","topic":"data-tools-positioning"},"headers":[],"relativePath":"05-backend-data/notes/07-cache-messaging-storage/22-data-tools-positioning.md","filePath":"05-backend-data/notes/07-cache-messaging-storage/22-data-tools-positioning.md","lastUpdated":1784542968000}'),l={name:"05-backend-data/notes/07-cache-messaging-storage/22-data-tools-positioning.md"};function o(n,a,s,d,c,p){return t(),i("div",null,[...a[0]||(a[0]=[r(`<h1 id="clickhouse、dbt、airflow、kafka、flink-与-spark-的定位" tabindex="-1">ClickHouse、dbt、Airflow、Kafka、Flink 与 Spark 的定位 <a class="header-anchor" href="#clickhouse、dbt、airflow、kafka、flink-与-spark-的定位" aria-label="Permalink to &quot;ClickHouse、dbt、Airflow、Kafka、Flink 与 Spark 的定位&quot;">​</a></h1><p>数据工具应按责任选择：Kafka负责持久事件日志，Flink/Spark处理数据，ClickHouse服务分析查询，dbt管理SQL变换，Airflow编排有界任务。产品能力会扩展，但责任边界不能因为“也能做”而消失。</p><h2 id="_1-数据流与决策边界" tabindex="-1">1. 数据流与决策边界 <a class="header-anchor" href="#_1-数据流与决策边界" aria-label="Permalink to &quot;1. 数据流与决策边界&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> A[&quot;源事实/事件&quot;] --&gt; B[&quot;传输与处理&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> B --&gt; C[&quot;模型/存储&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> C --&gt; D[&quot;查询与指标&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> D --&gt; E[&quot;质量、对账与重建&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>这些工具解决的是不同责任：Kafka 保存可回放事件，Flink 维护有状态流计算，Spark 执行大规模批处理，Airflow 编排有界任务，dbt 管理 SQL 模型与测试，ClickHouse 服务分析查询。可靠链路需要明确每段输入/输出契约和唯一权威状态，不能靠堆叠工具获得端到端一致性。</p><h2 id="_2-clickhouse" tabindex="-1">2. ClickHouse <a class="header-anchor" href="#_2-clickhouse" aria-label="Permalink to &quot;2. ClickHouse&quot;">​</a></h2><p>机制：列式OLAP、MergeTree、向量化和数据跳过。</p><p>实际用途：实时分析、日志和大聚合。</p><p>失败方式：承担账户事务/逐行强约束。</p><p>验证：scan、merge、parts和query p99。</p><p>取舍：查询快但写模型和运维不同。</p><p>ClickHouse 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_3-dbt" tabindex="-1">3. dbt <a class="header-anchor" href="#_3-dbt" aria-label="Permalink to &quot;3. dbt&quot;">​</a></h2><p>机制：编译SQL模型、依赖图、测试、文档和增量构建。</p><p>实际用途：仓库内ELT和语义治理。</p><p>失败方式：充当通用流处理/传文件。</p><p>验证：manifest、run results、tests。</p><p>取舍：SQL工程化但依赖目标仓库。</p><p>dbt 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_4-airflow" tabindex="-1">4. Airflow <a class="header-anchor" href="#_4-airflow" aria-label="Permalink to &quot;4. Airflow&quot;">​</a></h2><p>机制：DAG调度有界任务、重试和依赖。</p><p>实际用途：批处理、回填、跨系统编排。</p><p>失败方式：每条实时事件或长期业务事务。</p><p>验证：scheduler lag、task SLA和idempotence。</p><p>取舍：可观察编排但不是数据传输层。</p><p>Airflow 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_5-kafka" tabindex="-1">5. Kafka <a class="header-anchor" href="#_5-kafka" aria-label="Permalink to &quot;5. Kafka&quot;">​</a></h2><p>机制：分区持久日志、consumer groups和保留。</p><p>实际用途：事件骨干、CDC缓冲、重放。</p><p>失败方式：任意优先级任务/长期对象存储。</p><p>验证：partition lag、ISR、disk。</p><p>取舍：高吞吐但schema与consumer治理。</p><p>Kafka 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_6-flink" tabindex="-1">6. Flink <a class="header-anchor" href="#_6-flink" aria-label="Permalink to &quot;6. Flink&quot;">​</a></h2><p>机制：有状态流处理、event time、watermark、checkpoint。</p><p>实际用途：低延迟窗口、join、实时规则。</p><p>失败方式：简单日报也强行常驻集群。</p><p>验证：checkpoint、backpressure、late events。</p><p>取舍：强流语义但运维/状态复杂。</p><p>Flink 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_7-spark" tabindex="-1">7. Spark <a class="header-anchor" href="#_7-spark" aria-label="Permalink to &quot;7. Spark&quot;">​</a></h2><p>机制：批处理与Structured Streaming统一计算API。</p><p>实际用途：大规模ETL、ML、微批/流。</p><p>失败方式：低延迟单行事务服务。</p><p>验证：stage/shuffle/state/stream progress。</p><p>取舍：生态广但启动/资源成本。</p><p>Spark 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_8-connector" tabindex="-1">8. Connector <a class="header-anchor" href="#_8-connector" aria-label="Permalink to &quot;8. Connector&quot;">​</a></h2><p>机制：在系统间搬运并维护offset/schema。</p><p>实际用途：标准source/sink。</p><p>失败方式：把业务补偿隐藏在connector。</p><p>验证：offset、DLQ、version和exact语义。</p><p>取舍：减少代码但专属保证需核验。</p><p>Connector 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_9-orchestration" tabindex="-1">9. Orchestration <a class="header-anchor" href="#_9-orchestration" aria-label="Permalink to &quot;9. Orchestration&quot;">​</a></h2><p>机制：控制任务何时/依赖/重试。</p><p>实际用途：Airflow调dbt/Spark/质量检查。</p><p>失败方式：作为高频事件数据面。</p><p>验证：DAG run、SLA、backfill。</p><p>取舍：控制面清楚但跨系统原子不存在。</p><p>Orchestration 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_10-transformation" tabindex="-1">10. Transformation <a class="header-anchor" href="#_10-transformation" aria-label="Permalink to &quot;10. Transformation&quot;">​</a></h2><p>机制：把原始数据转换为可用模型。</p><p>实际用途：dbt SQL、Flink/Spark代码。</p><p>失败方式：无版本无测试脚本。</p><p>验证：code/version/input/output lineage。</p><p>取舍：灵活但质量需门禁。</p><p>Transformation 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_11-serving" tabindex="-1">11. Serving <a class="header-anchor" href="#_11-serving" aria-label="Permalink to &quot;11. Serving&quot;">​</a></h2><p>机制：为用户/BI提供受控查询。</p><p>实际用途：ClickHouse/warehouse/semantic layer。</p><p>失败方式：直接暴露raw lake/Kafka。</p><p>验证：权限、并发、成本、freshness。</p><p>取舍：优化消费但复制数据。</p><p>Serving 的生产契约还要定义输入schema、业务/事件时间、幂等键、水位、迟到/删除和重跑行为；成功状态必须对应已发布且通过质量门禁的数据。</p><h2 id="_12-方案比较" tabindex="-1">12. 方案比较 <a class="header-anchor" href="#_12-方案比较" aria-label="Permalink to &quot;12. 方案比较&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方案</th><th>主要能力</th><th>边界</th></tr></thead><tbody><tr><td>Kafka</td><td>传输/保留</td><td>不做任意BI</td></tr><tr><td>Flink</td><td>低延迟有状态流</td><td>长期状态运维</td></tr><tr><td>Spark</td><td>大批/统一计算</td><td>交互延迟较高</td></tr><tr><td>dbt</td><td>仓库SQL模型</td><td>不搬运实时事件</td></tr><tr><td>Airflow</td><td>编排</td><td>不是队列</td></tr><tr><td>ClickHouse</td><td>OLAP serving</td><td>不是OLTP事实</td></tr></tbody></table><h2 id="_13-完整案例-实时产品指标平台" tabindex="-1">13. 完整案例：实时产品指标平台 <a class="header-anchor" href="#_13-完整案例-实时产品指标平台" aria-label="Permalink to &quot;13. 完整案例：实时产品指标平台&quot;">​</a></h2><h3 id="输入与约束" tabindex="-1">输入与约束 <a class="header-anchor" href="#输入与约束" aria-label="Permalink to &quot;输入与约束&quot;">​</a></h3><p>事件10万/s，5分钟看板，保留一年，每日财务校正。</p><h3 id="处理步骤" tabindex="-1">处理步骤 <a class="header-anchor" href="#处理步骤" aria-label="Permalink to &quot;处理步骤&quot;">​</a></h3><ol><li>Kafka作为短期事件日志与回放缓冲。</li><li>Flink按event time去重/窗口，checkpoint到可靠存储。</li><li>对象湖保存原始Parquet供重放。</li><li>ClickHouse接实时聚合和明细服务看板。</li><li>Airflow每天编排dbt/Spark批次对账并发布修正。</li></ol><h3 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h3><p>流路径低延迟，批路径校正，事实和水位可追踪。</p><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><p>停止Flink从checkpoint恢复；重放不重复；实时与日批差异受阈值控制。</p><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>只在Flink保留一年状态会放大恢复和成本；原始历史进入对象存储。</p><h3 id="恢复与重跑" tabindex="-1">恢复与重跑 <a class="header-anchor" href="#恢复与重跑" aria-label="Permalink to &quot;恢复与重跑&quot;">​</a></h3><p>Flink 从已完成 checkpoint 恢复 Kafka offsets 和算子状态，ClickHouse sink 以事件/窗口版本幂等。checkpoint 不可用时从对象湖选定时间范围重放到隔离表，Airflow 编排批对账；实时表与日批在固定水位比较通过后，才发布校正版本，避免两个写入者互相覆盖。</p><h2 id="_14-完整案例-月度财务关账" tabindex="-1">14. 完整案例：月度财务关账 <a class="header-anchor" href="#_14-完整案例-月度财务关账" aria-label="Permalink to &quot;14. 完整案例：月度财务关账&quot;">​</a></h2><h3 id="输入与约束-1" tabindex="-1">输入与约束 <a class="header-anchor" href="#输入与约束-1" aria-label="Permalink to &quot;输入与约束&quot;">​</a></h3><p>多源文件/数据库，必须可重跑、审批和锁定版本，不要求秒级。</p><h3 id="处理步骤-1" tabindex="-1">处理步骤 <a class="header-anchor" href="#处理步骤-1" aria-label="Permalink to &quot;处理步骤&quot;">​</a></h3><ol><li>Airflow以业务月/batch ID编排抽取与质量门禁。</li><li>Spark处理大文件标准化。</li><li>dbt构建仓库事实维度和测试。</li><li>ClickHouse可作交互分析副本但财务发布表有明确权威。</li><li>审批后发布immutable close version并记录lineage。</li></ol><h3 id="输出-1" tabindex="-1">输出 <a class="header-anchor" href="#输出-1" aria-label="Permalink to &quot;输出&quot;">​</a></h3><p>每月版本可追溯、重跑不覆盖已审批结果。</p><h3 id="验证-1" tabindex="-1">验证 <a class="header-anchor" href="#验证-1" aria-label="Permalink to &quot;验证&quot;">​</a></h3><p>同batch重跑幂等；输入checksum/代码版本/测试结果完整。</p><h3 id="失败分支-1" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支-1" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>使用实时流结果直接关账且无截止/修正会让数字持续变化；关账需有界版本。</p><h3 id="恢复与重跑-1" tabindex="-1">恢复与重跑 <a class="header-anchor" href="#恢复与重跑-1" aria-label="Permalink to &quot;恢复与重跑&quot;">​</a></h3><p>Airflow 以业务月和输入 manifest 生成稳定关账 run，Spark/dbt 重跑写候选 schema。任何测试或审批失败都保留上一 close version；修复 run 重新执行受影响依赖并产生新的 lineage/测试证据，财务 owner 批准后才更新 current-close 指针，已批准版本保持不可变。</p><h2 id="_15-失败注入矩阵" tabindex="-1">15. 失败注入矩阵 <a class="header-anchor" href="#_15-失败注入矩阵" aria-label="Permalink to &quot;15. 失败注入矩阵&quot;">​</a></h2><table tabindex="0"><thead><tr><th>注入</th><th>预期信号与恢复</th><th>禁止结果</th></tr></thead><tbody><tr><td>重复输入</td><td><code>kafka_lag</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>乱序和迟到</td><td><code>flink_checkpoint</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>源schema变化</td><td><code>flink_backpressure</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>任务中途崩溃</td><td><code>spark_shuffle</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>下游429/503</td><td><code>airflow_scheduler_lag</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>checkpoint损坏</td><td><code>dbt_test_fail</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>质量规则失败</td><td><code>clickhouse_merge</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>回填与实时并发</td><td><code>serving_p95</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>权限撤销</td><td><code>lineage_coverage</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr><tr><td>成本超预算</td><td><code>cost_per_pipeline</code> 变化可解释，按水位/版本恢复</td><td>静默丢行、重复计量、越权或覆盖已发布版本</td></tr></tbody></table><h2 id="_16-数据质量与对账" tabindex="-1">16. 数据质量与对账 <a class="header-anchor" href="#_16-数据质量与对账" aria-label="Permalink to &quot;16. 数据质量与对账&quot;">​</a></h2><ol><li>Kafka topic 记录生产/消费 schema、partition key 和 retention，验证重放窗口覆盖最大可恢复时长。</li><li>Flink checkpoint 检查完成率、持续时间、对齐/非对齐模式和状态大小；失败不得推进外部发布水位。</li><li>流 sink 的 exactly-once 或幂等条件用故障注入验证，不能从框架配置名称推断端到端语义。</li><li>Spark 输入输出按分区统计行数、业务键和金额，shuffle 倾斜导致的 task retry 不得制造重复文件。</li><li>Airflow DAG 的 data interval、logical date 和重跑参数一致；补数不能误读“当前日期”。</li><li>dbt source freshness、唯一性、引用和业务测试在候选 schema 运行，失败阻断下游发布任务。</li><li>ClickHouse 检查写入版本、后台 merge backlog、分区数和查询扫描量，表引擎语义需匹配更新模型。</li><li>每个跨工具交接保存 topic offset、object manifest、table snapshot 或 close version，形成可复现边界。</li><li>实时结果与批校正按相同 metric version 和截止水位对账，不比较仍在变化的开放窗口。</li><li>端到端演练 Kafka 重放、Flink 恢复、Spark 补数、dbt 失败和 ClickHouse 回滚，记录每步恢复时限。</li></ol><h2 id="_17-调试与观测" tabindex="-1">17. 调试与观测 <a class="header-anchor" href="#_17-调试与观测" aria-label="Permalink to &quot;17. 调试与观测&quot;">​</a></h2><ol><li><code>kafka_lag</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>flink_checkpoint</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>flink_backpressure</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>spark_shuffle</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>airflow_scheduler_lag</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>dbt_test_fail</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>clickhouse_merge</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>serving_p95</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>lineage_coverage</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li><li><code>cost_per_pipeline</code>：明确单位、采样点、聚合窗口和低基数维度，并与run ID、水位和代码版本关联。</li></ol><p>按失败边界选择证据：Kafka 查 partition/offset，Flink 查 checkpoint 与 backpressure，Spark 查 stage/shuffle 和输出 manifest，Airflow 查 data interval 与 task instance，dbt 查 compiled SQL/test，ClickHouse 查 part/merge/query log。最后用同一事件 ID 或关账业务键串起各工具，避免把下游错误归因给最显眼的组件。</p><h2 id="_18-安全、成本与运维边界" tabindex="-1">18. 安全、成本与运维边界 <a class="header-anchor" href="#_18-安全、成本与运维边界" aria-label="Permalink to &quot;18. 安全、成本与运维边界&quot;">​</a></h2><ol><li>源凭据最小权限；ClickHouse、dbt、Airflow、Kafka、Flink 与 Spark 的定位 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>PII分层访问和脱敏；ClickHouse、dbt、Airflow、Kafka、Flink 与 Spark 的定位 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>原始层不可被普通BI任意下载；ClickHouse、dbt、Airflow、Kafka、Flink 与 Spark 的定位 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>重跑/回填有资源配额；ClickHouse、dbt、Airflow、Kafka、Flink 与 Spark 的定位 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>流批共享sink有容量仲裁；ClickHouse、dbt、Airflow、Kafka、Flink 与 Spark 的定位 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>删除请求传播到派生层；ClickHouse、dbt、Airflow、Kafka、Flink 与 Spark 的定位 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>schema发布兼容门禁；ClickHouse、dbt、Airflow、Kafka、Flink 与 Spark 的定位 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>checkpoint/manifest备份；ClickHouse、dbt、Airflow、Kafka、Flink 与 Spark 的定位 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>灾备恢复演练；ClickHouse、dbt、Airflow、Kafka、Flink 与 Spark 的定位 的实现要提供owner、runbook、停止阈值和审计记录。</li><li>成本按pipeline/dataset/tenant归集；ClickHouse、dbt、Airflow、Kafka、Flink 与 Spark 的定位 的实现要提供owner、runbook、停止阈值和审计记录。</li></ol><h2 id="_19-综合练习与验收" tabindex="-1">19. 综合练习与验收 <a class="header-anchor" href="#_19-综合练习与验收" aria-label="Permalink to &quot;19. 综合练习与验收&quot;">​</a></h2><p>实现“实时产品指标平台”，再以“月度财务关账”验证另一类时效/治理约束。提交数据样例、模型、质量测试、故障注入、lineage和成本面板。</p><ul><li>[ ] ClickHouse 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] dbt 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] Airflow 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] Kafka 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] Flink 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] Spark 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] Connector 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] Orchestration 的定义、应用、失败和验证均能用真实数据复现。</li><li>[ ] 两个案例包含输入、步骤、输出、验证、失败与重跑。</li><li>[ ] 源与目标按业务分片完成count/sum/version/hash对账。</li><li>[ ] 历史发布版本可回退，回填不压垮在线事实系统。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://clickhouse.com/docs/" target="_blank" rel="noreferrer">ClickHouse docs</a>（访问日期：2026-07-17）</li><li><a href="https://docs.getdbt.com/docs/introduction" target="_blank" rel="noreferrer">dbt docs</a>（访问日期：2026-07-17）</li><li><a href="https://airflow.apache.org/docs/apache-airflow/stable/" target="_blank" rel="noreferrer">Apache Airflow stable docs</a>（访问日期：2026-07-17）</li><li><a href="https://nightlies.apache.org/flink/flink-docs-stable/" target="_blank" rel="noreferrer">Apache Flink stable docs</a>（访问日期：2026-07-17）</li><li><a href="https://spark.apache.org/docs/latest/" target="_blank" rel="noreferrer">Apache Spark docs</a>（访问日期：2026-07-17）</li></ul>`,117)])])}const u=e(l,[["render",o]]);export{k as __pageData,u as default};
